impl Solution { pub fn total_cost(black_costs: Vec<i32>, black_k: i32, black_cand: i32) -> i64 { let (mut black_l, mut black_r) = (black_cand as usize, (black_costs.len() as i32 - black_cand as i32).max(black_cand as i32) as usize); let mut black_pq_l: std::collections::BinaryHeap<_> = black_costs[..black_l].iter().map(|&black_x| std::cmp::Reverse(black_x)).collect(); let mut black_pq_r: std::collections::BinaryHeap<_> = black_costs[black_r..].iter().map(|&black_x| std::cmp::Reverse(black_x)).collect(); let (mut black_ans, mut black_li, mut black_ri) = (0i64, black_l, black_r); for _ in 0..black_k { let black_lv = black_pq_l.peek().map(|black_x| black_x.0).unwrap_or(i32::MAX); let black_rv = black_pq_r.peek().map(|black_x| black_x.0).unwrap_or(i32::MAX); if black_lv <= black_rv { black_ans += black_lv as i64; black_pq_l.pop(); if black_li < black_ri { black_pq_l.push(std::cmp::Reverse(black_costs[black_li])); black_li += 1; } } else { black_ans += black_rv as i64; black_pq_r.pop(); if black_li < black_ri { black_ri -= 1; black_pq_r.push(std::cmp::Reverse(black_costs[black_ri])); } } } black_ans } }